// Construye el prompt para que GPT-4o personalice el email
const clinica = $input.first().json;

const systemPrompt = `Eres el asistente de ventas de AgutiDesigns, una agencia de diseño web y marketing digital basada en España.
Tu objetivo es redactar emails de ventas B2B en español, profesionales, naturales y personalizados.
El remitente se llama Alejandro.
El email debe:
- Tener un asunto llamativo y personalizado con el nombre de la clínica
- Abrirse mencionando algo específico de la clínica (ciudad, especialidad dental si se menciona, su web si tiene)
- Explicar brevemente qué puede hacer AgutiDesigns por ellos: web moderna, SEO local para captar pacientes, IA para responder consultas 24/7, campañas en Google/Meta
- Incluir prueba social: "trabajamos con clínicas en Barcelona, Madrid y Valencia que han aumentado sus citas un 40% en 3 meses"
- Cerrar con una llamada a la acción clara: responder al email o contactar por WhatsApp al 625204337
- Ser conciso: máximo 180 palabras en el cuerpo
- NO usar emojis en exceso, sonar humano

Devuelve SOLO un JSON válido con exactamente estas claves:
{
  "asunto": "string",
  "saludo": "string",
  "cuerpo_html": "string (HTML válido con <p>, <strong>, etc.)",
  "despedida": "string"
}`;

const userPrompt = `Redacta un email para esta clínica dental:
- Nombre: ${clinica.Nombre}
- Ciudad: ${clinica.Ciudad}
- Teléfono: ${clinica.Teléfono || 'no disponible'}
- Web: ${clinica.Web || 'no tienen web'}
- Valoración Google: ${clinica.Valoración || 'sin datos'} (${clinica['Nº Reseñas'] || '0'} reseñas)
- Resumen: ${clinica.Resumen || 'clínica dental'}`;

return [{
  json: {
    ...clinica,
    _systemPrompt: systemPrompt,
    _userPrompt:   userPrompt
  }
}];

const item   = $input.first().json;
const prev   = $('✍️ Preparar prompt de IA').first().json;

// Parsea la respuesta de GPT-4o
let emailData;
try {
  const rawContent = item.choices?.[0]?.message?.content || '{}';
  // Extrae el JSON aunque GPT ponga markdown (```json...```)
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  emailData = JSON.parse(jsonMatch ? jsonMatch[0] : rawContent);
} catch (e) {
  emailData = {
    asunto:      `Mejora la presencia online de ${prev.Nombre}`,
    saludo:      `Hola, me llamo Alejandro`,
    cuerpo_html: `<p>Me gustaría presentarles los servicios de AgutiDesigns para clínicas dentales.</p>`,
    despedida:   `Un saludo, Alejandro — AgutiDesigns`
  };
}

// Construye el email HTML completo
const htmlBody = `
<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8"><style>
  body { font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #333; line-height: 1.6; }
  .header { background: #0044FF; padding: 20px; text-align: center; }
  .header img { height: 40px; }
  .header h1 { color: white; font-size: 18px; margin: 8px 0 0; }
  .body { padding: 30px 24px; }
  .cta-btn { display: inline-block; background: #25D366; color: white; padding: 12px 28px;
             border-radius: 8px; text-decoration: none; font-weight: bold; margin: 16px 0; }
  .footer { background: #f5f5f5; padding: 16px 24px; font-size: 12px; color: #888; }
  .footer a { color: #0044FF; }
</style></head>
<body>
  <div class="header">
    <h1>AgutiDesigns — Diseño Web &amp; Marketing Digital</h1>
  </div>
  <div class="body">
    <p>${emailData.saludo},</p>
    ${emailData.cuerpo_html}
    <a href="https://wa.me/34625204337?text=${encodeURIComponent('Hola Alejandro, he recibido tu email sobre ' + prev.Nombre + '. Me gustaría saber más.')}" class="cta-btn">
      💬 Contactar por WhatsApp
    </a>
  </div>
  <div class="footer">
    <p>${emailData.despedida}</p>
    <p>AgutiDesigns · <a href="https://agutidesigns.io">agutidesigns.io</a> · +34 625 204 337</p>
    <p style="font-size:10px">Si no deseas recibir más comunicaciones de este tipo, responde con el asunto <strong>BAJA</strong>.
    Tratamos tus datos conforme al RGPD. Email comercial B2B conforme a la LSSI-CE art. 21.2.</p>
  </div>
</body></html>`;

return [{
  json: {
    ...prev,
    _asunto:    emailData.asunto,
    _htmlBody:  htmlBody,
    _systemPrompt: undefined,
    _userPrompt:   undefined
  }
}];

// Logging de resumen por si quieres monitorizar
const item = $input.first().json;
console.log(`✅ Email enviado a: ${item.Nombre} <${item.Email}> — ${item._asunto}`);
return [$input.first()];
